class Solution:
    def solve(self, pages: list[int], m: int) -> int:
        if m > len(pages):
            return -1
        low = max(pages)
        high = sum(pages)
        def can_allocate(limit: int) -> bool:
            required = 1
            current = 0
            for p in pages:
                if current + p <= limit:
                    current += p
                else:
                    required += 1
                    current = p
                    if required > m:
                        return False
            return True
        answer = high
        while low <= high:
            mid = (low + high) // 2
            if can_allocate(mid):
                answer = mid
                high = mid - 1
            else:
                low = mid + 1
        return answer

