#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(vector<int>& pages, int m) {
        if (m > (int)pages.size()) return -1;
        int low = *max_element(pages.begin(), pages.end());
        long long high = 0;
        for (int p : pages) high += p;
        auto canAllocate = [&](long long limit) {
            int required = 1;
            long long current = 0;
            for (int p : pages) {
                if (current + p <= limit) {
                    current += p;
                } else {
                    ++required;
                    current = p;
                    if (required > m) return false;
                }
            }
            return true;
        };
        long long ans = high;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            if (canAllocate(mid)) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return (int)ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, m, len;
    if (!(cin >> n)) return 0;
    if (!(cin >> m)) return 0;
    if (!(cin >> len)) return 0;
    vector<int> pages(len);
    for (int i = 0; i < len; ++i) cin >> pages[i];
    Solution sol;
    cout << sol.solve(pages, m) << "\n";
    return 0;
}
